+
+        // Clone and change theme
+        let modified = original.clone().theme("InspiredGitHub");
+
+        // Original should be unchanged
+        assert_eq!(original.theme_name, "base16-ocean.dark");
+        assert_eq!(modified.theme_name, "InspiredGitHub");
